// ShellWithContext cria um ShellLayout com contexto e sidebar opcional
func ShellWithContext(ctx goContext.Context, config ShellConfig, content templ.Component) templ.Component {
	// Get user email from context
	userEmail, err := appcontext.GetUserEmail(ctx)
	if err != nil {
		userEmail = "user@example.com"
	}
	config.UserEmail = userEmail

	return Shell(config, content)
}

